    if (total <= 7) {
      var r = [];
      for (var i = 1; i <= total; i++) r.push(i);
      return r;
    }
    var pages = [1];
    var lo = Math.max(2, current - PAGE_WINDOW);
    var hi = Math.min(total - 1, current + PAGE_WINDOW);
    if (lo > 2) pages.push("...");
    for (var j = lo; j <= hi; j++) pages.push(j);
    if (hi < total - 1) pages.push("...");
    pages.push(total);
    return pages;
  }

