  // ── Pagination ─────────────────────────────────────────────

  function getVisiblePageRows(state) {
    if (state.pageSize <= 0) return state.filteredRows;
    var start = (state.currentPage - 1) * state.pageSize;
    return state.filteredRows.slice(start, start + state.pageSize);
