    } else if (hasPlaceholders && state._rowHeightMeasured) {
      // Apply stored height to placeholder rows
      var placeholders = tbody.querySelectorAll(".gd-tbl-placeholder-row td");
      for (var ph = 0; ph < placeholders.length; ph++) {
