      for (var i = 0; i < state.sortCols.length; i++) {
        var sc = state.sortCols[i];
        var cmp = compareValues(a[sc.idx], b[sc.idx], state.columns[sc.idx].dtype);
        if (cmp !== 0) return sc.dir === "asc" ? cmp : -cmp;
