  function compareValues(a, b, dtype) {
    // Nulls always last
    if (a == null && b == null) return 0;
    if (a == null) return 1;
    if (b == null) return -1;

    var numericTypes = {
      i8: 1, i16: 1, i32: 1, i64: 1, u8: 1, u16: 1, u32: 1, u64: 1,
      f16: 1, f32: 1, f64: 1, dec: 1
