    if (numericTypes[dtype]) {
      return (a - b) || 0;
    }
    if (dtype === "bool") {
      return (a === b) ? 0 : (a ? 1 : -1);
    }
    if (dtype === "date" || dtype === "dtime") {
      var da = new Date(a), db = new Date(b);
      return da.getTime() - db.getTime();
    }
    // String: locale-aware comparison
    return String(a).localeCompare(String(b));
