  function getHighlightQuery(state, colIdx) {
    for (var i = 0; i < state.filterTokens.length; i++) {
      var t = state.filterTokens[i];
      if (t.colIdx === colIdx && t.op === "contains" && t.value) {
        return t.value;
      }
    }
    return "";
  }

